arguments.argument:
if global.gamePaused=false
{
  speed=bulletSpeed
  if direction>=270
    image_angle-=15
  else
    image_angle+=15
  
  if isCollisionTop(1)
    hitWall=1
  if isCollisionBottom(1)
    hitWall=2
  if isCollisionLeft(1)
    hitWall=3
  if isCollisionRight(1)
    hitWall=4
  
  if hitWall>=1
  {
    instance_destroy()
  }
}
else
  speed=0
